#!/usr/bin/env bash`n# ddd_full_scan.sh - Полный DDD анализ репозитория`n`n# Используем относительные пути для совместимости с разными ОС`ncd "$(dirname "$0")/.."`n`n# Проверка Python`nif ! command -v python &> /dev/null; then`n    echo "❌ Python не найден"`n    exit 1`nfi`n`necho "=================================================="`necho "  🏗️  ПОЛНЫЙ DDD АНАЛИЗ РЕПОЗИТОРИЯ"`necho "=================================================="`necho ""`necho "📋 Анализируются:"`necho "   - Доменные контексты (Bounded Contexts)"`necho "   - Сущности и агрегаты"`necho "   - Сервисы и репозитории"`necho "   - API контракты"`necho "   - Зависимости между сервисами"`necho "   - Архитектурные проблемы"`necho ""`n`n# Запускаем анализатор`necho "🔍 Запуск анализа..."`npython scripts/ddd_analyzer.py .`n`necho ""`necho "✅ Анализ завершен!"`necho ""`necho "📄 Результаты:"`necho "   - ddd_analysis_report.json (детальный JSON)"`necho "   - ddd_analysis_report.txt (человеко-читаемый отчет)"`necho ""`necho "📊 Быстрая статистика:"`nif [ -f "ddd_analysis_report.txt" ]; then`n    cat ddd_analysis_report.txt | head -50`nfi
